export default function HeroBanner() {
  return (
    <section className="relative bg-green-800 text-white h-[80vh] flex flex-col justify-center items-center text-center">
      <h1 className="text-5xl font-bold mb-4">Earth’s Exhale</h1>
      <p className="max-w-xl mb-6">Symbolizes the purity and calm of the Earth’s breath!</p>
      <div className="flex gap-4">
        <button className="bg-green-600 px-6 py-2 rounded hover:bg-green-700">Buy Now</button>
        <button className="border border-white px-6 py-2 rounded hover:bg-white hover:text-green-800">Explore</button>
      </div>
    </section>
  );
}
